'use client'

import React, { useState, useMemo } from 'react';
import CourseCard from './CourseCard';
import type { Course } from '../types/contentful';
import Box from '@mui/material/Box';
import Alert from '@mui/material/Alert';
import Stack from '@mui/material/Stack';
import TextField from '@mui/material/TextField';
import InputAdornment from '@mui/material/InputAdornment';
import Typography from '@mui/material/Typography';
import SearchIcon from '@mui/icons-material/Search';

interface CourseListProps {
    courses: Course[];
}

const CourseList: React.FC<CourseListProps> = ({ courses }) => {
    const [searchInput, setSearchInput] = useState('');

    // Filter courses based on search input - live search as user types
    const filteredCourses = useMemo(() => {
        if (!courses) return [];
        if (!searchInput.trim()) return courses;

        const searchLower = searchInput.toLowerCase().trim();
        return courses.filter(course => {
            const title = (course.fields?.pageTitle ?? '').toLowerCase();
            const intro = (course.fields?.introduction ?? '').toLowerCase();
            const slug = (course.fields?.slug ?? '').toLowerCase();

            return title.includes(searchLower) ||
                intro.includes(searchLower) ||
                slug.includes(searchLower);
        });
    }, [courses, searchInput]);

    return (
        <Box sx={{ width: '100%' }}>
            {/* Search Section */}
            <Box display="flex" justifyContent="center" mb={4}>
                <TextField
                    value={searchInput}
                    onChange={(e) => setSearchInput(e.target.value)}
                    placeholder="Search courses by keyword..."
                    variant="outlined"
                    sx={{ width: 600, maxWidth: '100%' }}
                    InputProps={{
                        startAdornment: (
                            <InputAdornment position="start">
                                <SearchIcon />
                            </InputAdornment>
                        ),
                    }}
                />
            </Box>

            {/* Results Count */}
            {searchInput && (
                <Box display="flex" justifyContent="center" mb={2}>
                    <Typography variant="body2" color="text.secondary">
                        Found {filteredCourses.length} course{filteredCourses.length !== 1 ? 's' : ''}
                    </Typography>
                </Box>
            )}

            {/* Results */}
            {filteredCourses.length === 0 ? (
                <Box display="flex" justifyContent="center" p={4}>
                    <Alert severity="info">
                        {searchInput
                            ? `No courses found matching "${searchInput}". Try different keywords.`
                            : 'No courses available.'}
                    </Alert>
                </Box>
            ) : (
                <Stack spacing={3} alignItems="center" sx={{ width: '100%' }}>
                    {filteredCourses.map(course => (
                        <CourseCard key={course.sys.id} course={course} />
                    ))}
                </Stack>
            )}
        </Box>
    );
};

export default CourseList;